const contacts = [
  { label: "Email", value: "Rezasaputradesky@gmail.com", href: "mailto:Rezasaputradesky@gmail.com", icon: Mail },
  { label: "WhatsApp", value: "Chat langsung", href: "#", icon: MessageCircle },
  { label: "LinkedIn", value: "Reza Saputra Desky", href: "#", icon: LinkedinIcon },
  { label: "Instagram", value: "reza_dsky", href: "#", icon: InstagramIcon },
];



export default function ContactPage() {
  return (
    <section className="min-h-screen px-6 py-16 md:py-24 animate-in">
      <div className="flex flex-col items-center text-center">
        <div className="mb-4 flex size-12 items-center justify-center rounded-xl bg-primary/10 text-primary">
          <Mail className="size-5" />
        </div>
        <h1 className="text-2xl font-bold tracking-tight sm:text-3xl">Contact</h1>
        <p className="mt-3 text-sm text-muted-foreground max-w-lg">Let&apos;s work together — reach out and say hello!</p>
      </div>

      <div className="mt-12 grid gap-4 sm:grid-cols-2 animate-stagger">
        {contacts.map((item, i) => {
          const Icon = item.icon;
          return (
            <a
              key={item.label}
              href={item.href}
              style={{ "--i": i } as React.CSSProperties}
              className={`group flex items-center gap-4 rounded-xl ${glassCard} ${glassCardHover} p-5`}
            >
              <div className="flex size-12 shrink-0 items-center justify-center rounded-xl bg-primary/10 text-primary transition-all duration-300 group-hover:bg-primary group-hover:text-primary-foreground group-hover:scale-110">
                <Icon className="size-5" />
              </div>
              <div className="min-w-0 flex-1">
                <p className="text-xs text-muted-foreground">{item.label}</p>
                <p className="text-sm font-medium truncate group-hover:text-primary transition-colors">{item.value}</p>
              </div>
            </a>
          );
        })}
      </div>

      <div className="mt-12 flex items-center justify-center gap-2 text-xs text-muted-foreground animate-in-fade">
        <MapPin className="size-3.5" />
        Banda Aceh, Indonesia
      </div>
    </section>
  );
}


